/* Each icon has neon gradient (#fbbf24 → #d97706), teal gradient, and glow filters */

import React from "react";

// shared defs block
function GlowDefs({ id }: { id: string }) {
  return (
    <defs>
      <linearGradient id={`neon-${id}`} x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#fbbf24" />
        <stop offset="100%" stopColor="#d97706" />
      </linearGradient>
      <linearGradient id={`teal-${id}`} x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#14b8a6" />
        <stop offset="100%" stopColor="#0d9488" />
      </linearGradient>
      <filter id={`glow-${id}`}>
        <feGaussianBlur stdDeviation="1.5" result="blur" />
        <feMerge>
          <feMergeNode in="blur" />
          <feMergeNode in="SourceGraphic" />
        </feMerge>
      </filter>
    </defs>
  );
}

type IconProps = {
  size?: number;
  className?: string;
};

