// arrays & hashing — magnifying glass with hash
export function IconArrays({ size = 18, className }: IconProps) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      className={className}
    >
      <GlowDefs id="arr" />
      <circle
        cx="10"
        cy="10"
        r="6"
        stroke={`url(#neon-arr)`}
        strokeWidth="1.5"
        filter={`url(#glow-arr)`}
      />
      <line
        x1="14.5"
        y1="14.5"
        x2="20"
        y2="20"
        stroke={`url(#neon-arr)`}
        strokeWidth="1.5"
        strokeLinecap="round"
      />
      <text x="7" y="13" fontSize="8" fill={`url(#neon-arr)`} fontWeight="bold">
        #
      </text>
    </svg>
  );
}

// advanced matrix — 3x3 grid
export function IconMatrix({ size = 18, className }: IconProps) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      className={className}
    >
      <GlowDefs id="mtx" />
      <g filter={`url(#glow-mtx)`}>
        {[0, 1, 2].map((r) =>
          [0, 1, 2].map((c) => (
            <rect
              key={`${r}-${c}`}
              x={4 + c * 6}
              y={4 + r * 6}
              width="4"
              height="4"
              rx="0.5"
              fill={`url(#neon-mtx)`}
              opacity={r === c ? 1 : 0.5}
            />
          )),
        )}
      </g>
    </svg>
  );
}

